-- IL FRUTTO PROIBITO - Database MySQL
-- Generato automaticamente

SET NAMES utf8mb4;

DROP TABLE IF EXISTS products;
DROP TABLE IF EXISTS categories;
DROP TABLE IF EXISTS users;
DROP TABLE IF EXISTS bookings;
DROP TABLE IF EXISTS contacts;
DROP TABLE IF EXISTS gift_packages;

CREATE TABLE categories (id INT AUTO_INCREMENT PRIMARY KEY, name TEXT NOT NULL, slug VARCHAR(255) NOT NULL UNIQUE, icon TEXT NOT NULL, description TEXT, product_count INT NOT NULL DEFAULT 0, parent_id INT, sort_order INT NOT NULL DEFAULT 0) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

CREATE TABLE products (id INT AUTO_INCREMENT PRIMARY KEY, name TEXT NOT NULL, brand TEXT NOT NULL, category_id INT NOT NULL, category_name TEXT NOT NULL, description TEXT, price DECIMAL(10,2) NOT NULL, original_price DECIMAL(10,2), image_url TEXT NOT NULL, quantity TEXT NOT NULL, is_bio TINYINT(1) NOT NULL DEFAULT 0, is_vegan TINYINT(1) NOT NULL DEFAULT 0, is_featured TINYINT(1) NOT NULL DEFAULT 0, discount_percent INT, in_stock TINYINT(1) NOT NULL DEFAULT 1) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

CREATE TABLE users (id INT AUTO_INCREMENT PRIMARY KEY, name TEXT NOT NULL, email VARCHAR(255) NOT NULL UNIQUE, password_hash TEXT NOT NULL, created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

CREATE TABLE bookings (id INT AUTO_INCREMENT PRIMARY KEY, consultation_type TEXT NOT NULL, date TEXT NOT NULL, time TEXT NOT NULL, first_name TEXT NOT NULL, last_name TEXT NOT NULL, email TEXT NOT NULL, phone TEXT NOT NULL, notes TEXT, created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

CREATE TABLE contacts (id INT AUTO_INCREMENT PRIMARY KEY, name TEXT NOT NULL, email TEXT NOT NULL, phone TEXT, subject TEXT NOT NULL, message TEXT NOT NULL, created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

CREATE TABLE gift_packages (id INT AUTO_INCREMENT PRIMARY KEY, name TEXT NOT NULL, description TEXT NOT NULL, image_url TEXT NOT NULL, base_price DECIMAL(10,2) NOT NULL, max_products INT NOT NULL DEFAULT 5, is_christmas TINYINT(1) NOT NULL DEFAULT 0) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;



